(function () {
  function getSettings() {
    var d = {
      enabled: true,
      desktopPad: 6,
      mobilePad: 18,
      breakpoint: 640,
      marginTop: 24,
      marginBottom: 56,
      imagePosition: "top",
      forceHttps: true
    };
    var s = window.glBlogPostBanner || {};
    for (var k in s) d[k] = s[k];
    return d;
  }

  function getOgImage() {
    var el =
      document.querySelector('meta[property="og:image:secure_url"]') ||
      document.querySelector('meta[property="og:image"]') ||
      document.querySelector('meta[name="twitter:image"]') ||
      document.querySelector('meta[itemprop="image"]');
    return el && el.content ? el.content : "";
  }

  function normalizeSrc(src, forceHttps) {
    if (!src) return "";
    if (forceHttps) src = src.replace(/^http:\/\//i, "https://");
    return src;
  }

  function applySizing(banner, img, settings) {
    var isMobile = window.matchMedia("(max-width: " + settings.breakpoint + "px)").matches;
    var pad = isMobile ? settings.mobilePad : settings.desktopPad;

    banner.style.height = "0";
    banner.style.paddingTop = pad + "%";
    banner.style.paddingBottom = pad + "%";
    banner.style.marginTop = settings.marginTop + "px";
    banner.style.marginBottom = settings.marginBottom + "px";

    if (img) img.style.objectPosition = settings.imagePosition;
  }

  function insertBanner() {
    var settings = getSettings();
    if (!settings.enabled) return;

    var wrapper = document.querySelector(".blog-item-wrapper");
    if (!wrapper) return;

    if (wrapper.querySelector(".gl-post-banner")) return;

    var top = wrapper.querySelector(".blog-item-top-wrapper");
    if (!top) return;

    var src = normalizeSrc(getOgImage(), settings.forceHttps);
    if (!src) return;

    var banner = document.createElement("div");
    banner.className = "gl-post-banner";

    var img = document.createElement("img");
    img.className = "gl-post-banner__img";
    img.src = src;
    img.alt = (document.querySelector("h1.blog-item-title, h1.blog-title, h1") || {}).textContent || "";
    img.loading = "lazy";
    img.decoding = "async";

    banner.appendChild(img);
    top.insertAdjacentElement("afterend", banner);

    applySizing(banner, img, settings);

    window.addEventListener("resize", function () {
      applySizing(banner, img, getSettings());
    });
  }

  function boot() {
    insertBanner();
    setTimeout(insertBanner, 300);
    setTimeout(insertBanner, 1200);
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", boot);
  else boot();

  window.addEventListener("load", boot);
  document.addEventListener("page:load", boot);
  document.addEventListener("page:change", boot);

  new MutationObserver(function () {
    insertBanner();
  }).observe(document.documentElement, { childList: true, subtree: true });
})();
